### Step 3: Implement the Game Logic

Now, let's implement the `Game` class to handle game logic, player turns, and win/draw detection.

```python
class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'B'
        self.selected_piece = None

    def get_valid_moves(self, piece, row, col):
        moves = []
        if piece.kinged or piece.color == self.current_player:
            # Normal move and capture for black
            if piece.color == 'B':
                if row + 1 < 8 and col - 1 >= 0 and self.board.board[row + 1][col - 1] is None:
                    moves.append((row + 1, col - 1))
                if row + 1 < 8 and col + 1 < 8 and self.board.board[row + 1][col + 1] is None:
                    moves.append((row + 1, col + 1))
                # Capture
                if row + 2 < 8 and col - 2 >= 0 and self.board.board[row + 2][col - 2] == 'W':
                    moves.append((row + 2, col - 2))
                if row + 2 < 8 and col + 2 < 8 and self.board.board[row + 2][col + 2] == 'W':
                    moves.append((row + 2, col + 2))
            # Normal move and capture for white
            if piece.color == 'W':
                if row - 1 >= 0 and col - 1 >= 0 and self.board.board[row - 1][col - 1] is None:
                    moves.append((row - 1, col - 1))
                if row - 1 >= 0 and col + 1 < 8 and self.board.board[row - 1][col + 1] is None:
                    moves.append((row - 1, col + 1))
                # Capture
                if row - 2 >= 0 and col - 2 >= 0 and self.board.board[row - 2][col - 2] == 'B':
                    moves.append((row - 2, col - 2))
                if row - 2 >= 0 and col + 2 < 8 and self.board.board[row - 2][col + 2] == 'B':
                    moves.append((row - 2, col + 2))
        return moves

    def make_move(self, start_pos, end_pos):
        piece = self.board.board[start_pos[0]][start_pos[1]]
        if piece is not None and piece.color == self.current_player:
            valid_moves = self.get_valid_moves(piece, start_pos[0], start_pos[1])
            if end_pos in valid_moves:
                if abs(start_pos[0] - end_pos[0]) == 2:
                    # Capture move
                    row_dir = (end_pos[0] - start_pos[0]) // 2
                    col_dir = (end_pos[1] - start_pos[1]) // 2
                    self.board.board[start_pos[0] + row_dir][start_pos[1] + col_dir] = None
                self.board.board[end_pos[0]][end_pos[1]] = piece
                self.board.board[start_pos[0]][start_pos[1]] = None
                if end_pos[0] == 7 and piece.color == 'B':
                    piece.make_king()
                elif end_pos[0] == 0 and piece.color == 'W':
                    piece.make_king()
                self.current_player = 'W' if self.current_player == 'B' else 'B'

    def is_game_over(self):
        # Check for win/draw
        return False

    def print_board(self):
        self.board.print_board()

